class MyCalendarThree {
    map<int, int> diff;
public:
    MyCalendarThree() {}

    int book(int startTime, int endTime) {
        ++diff[startTime];
        --diff[endTime];
        int cur = 0, ans = 0;
        for (const auto& [_, delta] : diff) {
            cur += delta;
            ans = max(ans, cur);
        }
        return ans;
    }
};
```
